class CdpClient {
  /** Namespace containing all EVM methods. */
  evm;
  /** Namespace containing all Solana methods. */
  solana;
  /** Namespace containing all Policies methods. */
  policies;
  /** Namespace containing all end user methods. */
  endUser;
  /** Namespace containing all webhook methods. */
  webhooks;
  /**
   * The CdpClient is the main class for interacting with the CDP API.
   *
   * There are a few required parameters that are configured in the [CDP Portal](https://portal.cdp.coinbase.com/projects/api-keys):
   * - **CDP Secret API Key** (`apiKeyId` & `apiKeySecret`): These are used to authenticate requests to the entire suite of
   *   APIs offered on Coinbase Developer Platform.
   *   [Read more about CDP API keys](https://docs.cdp.coinbase.com/get-started/docs/cdp-api-keys).
   * - **Wallet Secret** (`walletSecret`): This secret is used specifically to authenticate requests to `POST`, and `DELETE`
   *   endpoints in the EVM and Solana Account APIs.
   *
   * These parameters can be set as environment variables:
   * ```
   * CDP_API_KEY_ID=your-api-key-id
   * CDP_API_KEY_SECRET=your-api-key-secret
   * CDP_WALLET_SECRET=your-wallet-secret
   * ```
   *
   * Or passed as options to the constructor:
   *
   * ```typescript
   * const cdp = new CdpClient({
   *   apiKeyId: "your-api-key-id",
   *   apiKeySecret: "your-api-key-secret",
   *   walletSecret: "your-wallet-secret",
   * });
   * ```
   *
   * The CdpClient is namespaced by chain type: `evm` or `solana`.
   *
   * As an example, to create a new EVM account, use `cdp.evm.createAccount()`.
   *
   * To create a new Solana account, use `cdp.solana.createAccount()`.
   *
   * @param {CdpClientOptions} [options] - Configuration options for the CdpClient.
   */
  constructor(options = {}) {
    if (Number(process.versions.node.split(".")[0]) < 19) {
      throw new Error(`
Node.js version ${process.versions.node} is not supported. CDP SDK requires Node.js version 19 or higher. Please upgrade your Node.js version to use the CDP SDK.
We recommend using https://github.com/Schniz/fnm for managing your Node.js version.
        `);
    }
    const apiKeyId = options.apiKeyId ?? process.env.CDP_API_KEY_ID ?? process.env.CDP_API_KEY_NAME;
    const apiKeySecret = options.apiKeySecret ?? process.env.CDP_API_KEY_SECRET;
    const walletSecret = options.walletSecret ?? process.env.CDP_WALLET_SECRET;
    if (!apiKeyId || !apiKeySecret) {
      throw new Error(`

Missing required CDP Secret API Key configuration parameters.

You can set them as environment variables:

CDP_API_KEY_ID=your-api-key-id
CDP_API_KEY_SECRET=your-api-key-secret

You can also pass them as options to the constructor:

const cdp = new CdpClient({
  apiKeyId: "your-api-key-id",
  apiKeySecret: "your-api-key-secret",
});

If you're performing write operations, make sure to also set your wallet secret:

CDP_WALLET_SECRET=your-wallet-secret

This is also available as an option to the constructor:

const cdp = new CdpClient({
  apiKeyId: "your-api-key-id",
  apiKeySecret: "your-api-key-secret",
  walletSecret: "your-wallet-secret",
});

For more information, see: https://github.com/coinbase/cdp-sdk/blob/main/typescript/README.md#api-keys.
`);
    }
    CdpOpenApiClient.configure({
      ...options,
      apiKeyId,
      apiKeySecret,
      walletSecret,
      source: "sdk",
      sourceVersion: version
    });
    if (process.env.DISABLE_CDP_ERROR_REPORTING !== "true" || process.env.DISABLE_CDP_USAGE_TRACKING !== "true") {
      Analytics.identifier = apiKeyId;
    }
    this.evm = new EvmClient();
    this.solana = new SolanaClient();
    this.policies = new PoliciesClient();
    this.endUser = new EndUserClient();
    this.webhooks = new WebhooksClient();
  }
}
function createCdpClientOrThrow(options, context) {
  try {
    return new CdpClient({
      apiKeyId: options.cdpApiKeyId,
      apiKeySecret: options.cdpApiKeySecret,
      walletSecret: options.cdpWalletSecret
    });
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    throw new Error(`Failed to initialize CDP client for ${context}. ${errorMessage}

Please ensure you have set the required CDP credentials either:
1. As environment variables: CDP_API_KEY_ID, CDP_API_KEY_SECRET, CDP_WALLET_SECRET
2. As function parameters: cdpApiKeyId, cdpApiKeySecret, cdpWalletSecret

You can get these credentials from https://portal.cdp.coinbase.com/`);
  }
}
async function getExistingSmartWalletOrThrow(cdpClient, walletName, context) {
  try {
    const eoaAccount = await cdpClient.evm.getAccount({ name: walletName });
    if (!eoaAccount) {
      throw new Error(`EOA wallet "${walletName}" not found. The wallet must be created before executing a ${context}. Use getOrCreateSubscriptionOwnerWallet() to create the wallet first.`);
    }
    const smartWallet = await cdpClient.evm.getSmartAccount({
      name: walletName,
      // Same name as the EOA wallet
      owner: eoaAccount
    });
    if (!smartWallet) {
      throw new Error(`Smart wallet "${walletName}" not found. The wallet must be created before executing a ${context}. Use getOrCreateSubscriptionOwnerWallet() to create the wallet first.`);
    }
    return smartWallet;
  } catch (error) {
    if (error instanceof Error && error.message.includes("not found")) {
      throw error;
    }
    const errorMessage = error instanceof Error ? error.message : String(error);
    throw new Error(`Failed to get ${context} smart wallet "${walletName}": ${errorMessage}`);
  }
}
async function sendUserOpAndWait(networkSmartWallet, calls, paymasterUrl, timeoutSeconds, context) {
  try {
    const userOpResult = await networkSmartWallet.sendUserOperation({
      calls,
      ...paymasterUrl && { paymasterUrl }
    });
    const completedOp = await networkSmartWallet.waitForUserOperation({
      userOpHash: userOpResult.userOpHash,
      waitOptions: {
        timeoutSeconds
      }
    });
    if (completedOp.status === "failed") {
      throw new Error(`User operation failed: ${userOpResult.userOpHash}`);
    }
    const transactionHash = completedOp.transactionHash;
    if (!transactionHash) {
      throw new Error("No transaction hash received from operation");
    }
    return transactionHash;
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    throw new Error(`Failed to execute ${context} transaction with smart wallet: ${errorMessage}`);
  }
}
async function charge(options) {
  const { id, amount, testnet = false, cdpApiKeyId, cdpApiKeySecret, cdpWalletSecret, walletName = "subscription owner", paymasterUrl = process.env.PAYMASTER_URL, recipient, rpcUrl } = options;
  const cdpClient = createCdpClientOrThrow({ cdpApiKeyId, cdpApiKeySecret, cdpWalletSecret }, "subscription charge");
  const smartWallet = await getExistingSmartWalletOrThrow(cdpClient, walletName, "charge");
  const chargeCalls = await prepareCharge({ id, amount, testnet, recipient, rpcUrl });
  const network = testnet ? "base-sepolia" : "base";
  const networkSmartWallet = await smartWallet.useNetwork(network);
  const transactionHash = await sendUserOpAndWait(
    networkSmartWallet,
    chargeCalls,
    paymasterUrl,
    60,
    // Wait up to 60 seconds for the operation to complete
    "charge"
  );
  return {
    success: true,
    id: transactionHash,
    subscriptionId: id,
    amount: amount === "max-remaining-charge" ? "max" : amount,
    subscriptionOwner: smartWallet.address,
    ...recipient && { recipient }
  };
}
